<?php get_header(); if(have_posts()): while(have_posts()):the_post(); ?>
<div class="cdb-container"><?php cdb_output_breadcrumbs(); ?><article <?php post_class('single-article'); ?>><header><h1><?php the_title(); ?></h1><?php get_template_part('template-parts/post-meta'); ?></header><?php if(has_post_thumbnail()){ the_post_thumbnail('large',array('class'=>'featured-image')); } get_template_part('template-parts/affiliate-disclaimer'); if(cdb_should_show_medical_disclaimer()){ get_template_part('template-parts/medical-disclaimer'); } ?><div class="entry-content"><?php the_content(); ?></div><?php get_template_part('template-parts/author-box'); ?><nav class="post-nav"><?php previous_post_link('<span>%link</span>'); ?><?php next_post_link('<span>%link</span>'); ?></nav><?php get_template_part('template-parts/related-posts'); ?></article></div>
<?php endwhile; endif; get_footer(); ?>
